// Validate Input v4.0
const body = $input.first().json.body || $input.first().json;
const required = ['provider_id', 'service_id', 'start_time'];
for (const field of required) {
  if (!body[field]) {
    return [{ json: { success: false, error_code: 'MISSING_FIELD', error_message: `Missing: ${field}`, data: null, _meta: { source: 'WF2_v4', timestamp: new Date().toISOString() } }}];
  }
}
const provider_id = parseInt(body.provider_id, 10);
const service_id = parseInt(body.service_id, 10);
if (isNaN(provider_id) || isNaN(service_id)) {
  return [{ json: { success: false, error_code: 'INVALID_TYPE', error_message: 'provider_id/service_id must be numeric', data: null, _meta: { source: 'WF2_v4', timestamp: new Date().toISOString() } }}];
}
const duration = parseInt(body.duration_minutes || 60, 10);
const startDate = new Date(body.start_time);
const endDate = new Date(startDate.getTime() + duration * 60000);
const cleanTime = String(body.start_time).replace(/[^0-9]/g, '');
const idempotency_key = `booking_${provider_id}_${service_id}_${cleanTime}_${body.customer_id || body.chat_id || 'anon'}`.substring(0, 255);
return [{ json: { ctx: { provider_id, service_id, start_time: body.start_time, end_time: endDate.toISOString(), duration_minutes: duration, user_id: parseInt(body.user_id || 0, 10), customer_id: body.customer_id || null, chat_id: body.chat_id || null, event_title: body.event_title || 'Appointment', idempotency_key, _meta: { source: 'WF2_Booking_Orchestrator_v4', version: '4.0.0-internal', timestamp: new Date().toISOString() } } }}];

const items = $input.all();
const ctx = $('Validate Input').first().json.ctx;
const dup = (items.length > 0 && items[0].json.booking_id) ? items[0].json : null;
if (dup) {
  return [{ json: { success: true, error_code: null, error_message: null, data: { booking_id: dup.booking_id, status: dup.status, gcal_event_id: dup.gcal_event_id, is_duplicate: true }, _meta: ctx._meta }}];
}
return [{ json: { ctx, is_duplicate: false } }];

const ctx = $input.first().json.ctx;
const lock_key = `lock_${ctx.provider_id}_${ctx.start_time}`;
const owner_token = ctx.idempotency_key;
return [{ json: { ctx, lock_key, owner_token, lock_query: `INSERT INTO booking_locks (provider_id, start_time, lock_key, owner_token, expires_at, created_at) VALUES (${ctx.provider_id}, '${ctx.start_time}'::timestamptz, '${lock_key}', '${owner_token}', NOW() + INTERVAL '5 minutes', NOW()) ON CONFLICT (lock_key) DO UPDATE SET expires_at = NOW() + INTERVAL '5 minutes', updated_at = NOW() WHERE booking_locks.expires_at < NOW() RETURNING id, owner_token;` }}];

const items = $input.all();
const ctx = $('Build Lock Query').first().json.ctx;
const lock_key = $('Build Lock Query').first().json.lock_key;
const owner_token = $('Build Lock Query').first().json.owner_token;
const lock_acquired = (items.length > 0 && items[0].json.id) ? true : false;
if (!lock_acquired) {
  return [{ json: { success: false, error_code: 'LOCK_DENIED', error_message: 'Slot already booked', data: { lock_key }, _meta: ctx._meta, _needs_lock_release: false } }];
}
return [{ json: { ctx, lock_key, owner_token, lock_acquired: true } }];

const ctx = $input.first().json.ctx;
const lock_key = $input.first().json.lock_key;
const owner_token = $input.first().json.owner_token;
return [{ json: { ctx, lock_key, owner_token, cb_query: `SELECT allowed, failure_count FROM circuit_breaker WHERE service_id = 'google_calendar' LIMIT 1;` }}];

const items = $input.all();
const ctx = $('Build CB Query').first().json.ctx;
const lock_key = $('Build CB Query').first().json.lock_key;
const owner_token = $('Build CB Query').first().json.owner_token;
const cb_row = (items.length > 0 && items[0].json) ? items[0].json : null;
const cb_allowed = cb_row && cb_row.allowed === true;
if (!cb_allowed) {
  return [{ json: { success: false, error_code: 'CIRCUIT_BREAKER_OPEN', error_message: 'GCal service unavailable', data: { service: 'google_calendar', failure_count: cb_row?.failure_count || 0 }, _meta: ctx._meta, _needs_lock_release: true, lock_key, owner_token } }];
}
return [{ json: { ctx, lock_key, owner_token, cb_allowed: true } }];

const ctx = $input.first().json.ctx;
const lock_key = $input.first().json.lock_key;
const owner_token = $input.first().json.owner_token;
return [{ json: { ctx, lock_key, owner_token, avail_query: `SELECT COUNT(*) as count FROM bookings WHERE provider_id = ${ctx.provider_id} AND service_id = ${ctx.service_id} AND start_time = '${ctx.start_time}'::timestamptz AND status = 'CONFIRMED';` }}];

const items = $input.all();
const ctx = $('Build Avail Query').first().json.ctx;
const lock_key = $('Build Avail Query').first().json.lock_key;
const owner_token = $('Build Avail Query').first().json.owner_token;
const avail_row = (items.length > 0 && items[0].json) ? items[0].json : null;
const avail_count = parseInt(avail_row?.count || '0', 10);
const is_available = avail_count === 0;
if (!is_available) {
  return [{ json: { success: false, error_code: 'NO_AVAILABILITY', error_message: 'Slot not available', data: { provider_id: ctx.provider_id, service_id: ctx.service_id, start_time: ctx.start_time }, _meta: ctx._meta, _needs_lock_release: true, lock_key, owner_token } }];
}
return [{ json: { ctx, lock_key, owner_token, is_available: true } }];

const items = $input.all();
const ctx = $('Create GCal Event').first().json.ctx;
const lock_key = $('Create GCal Event').first().json.lock_key;
const owner_token = $('Create GCal Event').first().json.owner_token;
const gcal_row = (items.length > 0 && items[0].json) ? items[0].json : null;
const gcal_event_id = gcal_row?.id || null;
const gcal_success = !!gcal_event_id;
if (!gcal_success) {
  return [{ json: { success: false, error_code: 'GCAL_ERROR', error_message: gcal_row?.message || 'Failed to create GCal event', data: { service: 'google_calendar' }, _meta: ctx._meta, _needs_lock_release: true, lock_key, owner_token } }];
}
return [{ json: { ctx, lock_key, owner_token, gcal_event_id, gcal_success: true } }];

const items = $input.all();
const ctx = $('Create Booking').first().json.ctx;
const lock_key = $('Create Booking').first().json.lock_key;
const owner_token = $('Create Booking').first().json.owner_token;
const gcal_event_id = $('Create Booking').first().json.gcal_event_id;
