  return [{ json: { success: false, error_code: 'DB_ERROR', error_message: 'Failed to create booking', data: { gcal_event_id, needs_rollback: true, needs_lock_release: true }, _meta: ctx._meta, lock_key, owner_token } }];
}
return [{ json: { ctx, lock_key, owner_token, gcal_event_id, booking_id, booking_success: true } }];

const ctx = $('Process Booking').first().json.ctx;
const booking_id = $('Process Booking').first().json.booking_id;
const gcal_event_id = $('Process Booking').first().json.gcal_event_id;
return [{ json: { success: true, error_code: null, error_message: null, data: { booking_id, idempotency_key: ctx.idempotency_key, provider_id: ctx.provider_id, service_id: ctx.service_id, start_time: ctx.start_time, end_time: ctx.end_time, status: 'CONFIRMED', gcal_event_id, is_duplicate: false }, _meta: { source: 'WF2_Booking_Orchestrator_v4', timestamp: new Date().toISOString(), version: '4.0.0-internal' } }}];

const input = $input.first().json;
const error_response = { success: input.success || false, error_code: input.error_code || 'UNKNOWN_ERROR', error_message: input.error_message || 'An error occurred', data: input.data || null, _meta: input._meta || { source: 'WF2_v4', timestamp: new Date().toISOString() } };
if (input._needs_lock_release && input.lock_key) {
  return [{ json: { ...error_response, _release_lock: true, lock_key: input.lock_key, owner_token: input.owner_token } }];
}
return [{ json: error_response }];
